/// Resolves an external entity reference by reading the referenced file.
/// WARNING: This function resolves external entities which can lead to
/// XML External Entity (XXE) attacks. In production, external entity
/// resolution should be disabled or strictly sandboxed.
fn resolve_external_entity(system_id: &str, base_path: &str) -> Result<String, ConfigError> {
    // Construct the path relative to the base path
    let path = if system_id.starts_with('/') || system_id.starts_with("file://") {
        let clean_path = system_id.trim_start_matches("file://");
        clean_path.to_string()
    } else {
        format!("{}/{}", base_path, system_id)
    };

    let content = fs::read_to_string(&path)?;
    Ok(content)
}

/// Parses inline external entity definitions from the XML content.
/// Handles <!ENTITY name SYSTEM "uri"> declarations.
fn extract_entity_definitions(xml_content: &str) -> HashMap<String, String> {
    let mut entities = HashMap::new();

    // Simple regex-like extraction for ENTITY declarations in DOCTYPE
    if let Some(doctype_start) = xml_content.find("<!DOCTYPE") {
        if let Some(doctype_end) = xml_content[doctype_start..].find(']') {
            let doctype_section = &xml_content[doctype_start..doctype_start + doctype_end];

            let mut remaining = doctype_section;
            while let Some(entity_pos) = remaining.find("<!ENTITY") {
                let entity_section = &remaining[entity_pos..];
                if let Some(end_pos) = entity_section.find('>') {
                    let entity_decl = &entity_section[..end_pos + 1];
                    // Parse entity name and value
                    let parts: Vec<&str> = entity_decl.split_whitespace().collect();
                    if parts.len() >= 4 {
                        let name = parts[1];
                        if parts[2] == "SYSTEM" {
                            let uri = parts[3..].join(" ");
                            let uri = uri.trim_matches(|c| c == '"' || c == '\'' || c == '>');
                            entities.insert(name.to_string(), uri.to_string());
                        } else {
                            // Inline entity value
                            let value = parts[2..].join(" ");
                            let value = value.trim_matches(|c| c == '"' || c == '\'' || c == '>');
                            entities.insert(name.to_string(), value.to_string());
                        }
                    }
                    remaining = &remaining[entity_pos + end_pos + 1..];
                } else {
                    break;
                }
            }
        }
    }

    entities
}

/// Expands entity references in text content.
fn expand_entities(text: &str, entities: &HashMap<String, String>, base_path: &str) -> String {
    let mut result = text.to_string();

    for (name, uri_or_value) in entities {
        let entity_ref = format!("&{};", name);
        if result.contains(&entity_ref) {
            // Try to resolve as external entity (file reference)
            let replacement = if uri_or_value.ends_with(".xml")
                || uri_or_value.ends_with(".ent")
                || uri_or_value.starts_with("file://")
                || uri_or_value.contains('/')
            {
                resolve_external_entity(uri_or_value, base_path).unwrap_or_else(|_| uri_or_value.clone())
            } else {
                uri_or_value.clone()
            };
            result = result.replace(&entity_ref, &replacement);
        }
    }

    result
}

